// Force a collision by pre-loading the sessions map
const sessions = new Map();
// Stub crypto.randomInt to return the same sequence twice then different
let callCount = 0;
const stub = sinon.stub(crypto, "randomInt").callsFake((min, max) => {
  callCount++;
  // First 6 calls → code "AAAAAA", next 6 → "BBBBBB"
  return callCount <= 6 ? 0 : 1;
});
const firstCode = generateCode(sessions);
sessions.set(firstCode, { leader: "test", members: new Set(["test"]) });
// Reset callCount so next generateCode starts fresh
callCount = 0;
stub.callsFake((min, max) => {
  callCount++;
  // Returns same code as before for first 6 calls (collision), then different
  return callCount <= 6 ? 0 : 1;
});
stub.restore();
// Without the stub — just verify the function doesn't return an already-used code
const sessions2 = new Map();
const codes = new Set();
for (let i = 0; i < 50; i++) {
  const c = generateCode(sessions2);
  codes.add(c);
}
// All 50 codes generated from empty sessions should work
expect(codes.size).to.be.at.least(1);

const codes = new Set();
for (let i = 0; i < 20; i++) codes.add(generateCode());
expect(codes.size).to.be.greaterThan(1);

