const result = joinSession(sessions, "Bob", "ABCDEF");
expect(result).to.have.property("code", "ABCDEF");
expect(result).to.have.property("leader", "Alice");
expect(result.memberCount).to.equal(2);

const result = joinSession(sessions, "Bob", "ZZZZZZ");
expect(result.status).to.equal(404);
expect(result.error).to.include("not found");

const result = joinSession(sessions, "Alice", "ABCDEF");
expect(result.status).to.equal(409);
expect(result.error).to.include("already taken");

const result = joinSession(sessions, "Bob", "");
expect(result.status).to.equal(400);
expect(result.error).to.include("required");

const result = joinSession(sessions, "  Bob  ", "ABCDEF");
expect(result.memberCount).to.equal(2);
expect(sessions.get("ABCDEF").members.has("Bob")).to.be.true;

joinSession(sessions, "Bob", "ABCDEF");
joinSession(sessions, "Charlie", "ABCDEF");
expect(sessions.get("ABCDEF").members.size).to.equal(3);

